var PGobject = Packages.org.postgresql.util.PGobject;

function toJsonb(value) {
    var jsonbObj = new PGobject();
    jsonbObj.setType("jsonb");

	if (typeof value === "object") {
        value = JSON.stringify(value);
    }

    jsonbObj.setValue(value);
    logger.info("jsonbObj: " + jsonbObj);
    return jsonbObj;
}


function saveCcdaPayload(interactionId, tenantId, requestUri, payloadJson, operation) {

	logger.info(
    "interactionId: " + interactionId +
    ", tenantId: " + tenantId +
    ", requestUri: " + requestUri +
    ", operation: " + operation
	);

	var DriverManager = java.sql.DriverManager;
	var conn = null;
	var stmt = null;

	try {

	    // Database connection details
		var dbUrl = globalMap.get('jdbcUrl');
		var dbUser = globalMap.get('jdbcUsername');
		var dbPassword = globalMap.get('jdbcPassword');

		var ccdaAuthoringDevice = channelMap.get('ehrVendor');
	     logger.info("ccdaAuthoringDevice ================***: " + ccdaAuthoringDevice);
	     //If any error happens in between, find the ccda source type from the input file
	if (operation === "saveOgCCDAPayload" && typeof ccdaAuthoringDevice === 'undefined' || ccdaAuthoringDevice === "" || ccdaAuthoringDevice === null){
		if (/epic/i.test(payloadJson)) { channelMap.put('ehrVendor', 'Epic'); }
		if (/medent/i.test(payloadJson)) { channelMap.put('ehrVendor', 'Medent'); }
		if (/athenahealth/i.test(payloadJson)) { channelMap.put('ehrVendor', 'AthenaHealth'); }
		ccdaAuthoringDevice = channelMap.get('ehrVendor');
		logger.info("ccdaAuthoringDevice ================***: " + ccdaAuthoringDevice);
	}
	if (ccdaAuthoringDevice == 'Other') { ccdaAuthoringDevice = null; }

		//Devl
	    conn = DriverManager.getConnection(dbUrl, dbUser, dbPassword);

	    logger.info("Database connection established successfully.");

		var sql = "select techbd_udi_ingress.register_interaction_ccda_request(?::text,?::text,?::jsonb,?::text,?::text,?::jsonb,?::text,?::text,?::jsonb,?::text,?::text,?::text,?::text,?::text,?::text,?::text,?,?::text,?,?::text,?::text,?::text,?::text,?::text,?::text,?::text,?::text,?::text,?::text)";
	    stmt = conn.prepareCall(sql);

		stmt.setString(1, interactionId);
		stmt.setString(2, requestUri);		
		if(operation === "saveOgCCDAPayload"){
			stmt.setObject(3, toJsonb(JSON.stringify({
			    nature: 'Original CCDA Payload',
			    tenant_id: tenantId
			})), java.sql.Types.OTHER);
			stmt.setString(4, "NONE");	
			stmt.setString(5, "CCDA_ACCEPT");		
		} else if (operation === "saveValidationSuccess") {
			stmt.setObject(3, toJsonb(JSON.stringify({
			    nature: 'CCDA Validation Result',
			    tenant_id: tenantId
			})), java.sql.Types.OTHER);
			stmt.setString(4, "CCDA_ACCEPT");	
			stmt.setString(5, "VALIDATION_SUCCESS");
		} else if (operation === "saveConversionSuccess") {
			stmt.setObject(3, toJsonb(JSON.stringify({
			    nature: 'Converted to FHIR',
			    tenant_id: tenantId
			})), java.sql.Types.OTHER);
			stmt.setString(4, "VALIDATION_SUCCESS");	
			stmt.setString(5, "CONVERTED_TO_FHIR");
		} else {
			stmt.setObject(3, toJsonb(JSON.stringify({
			    nature: 'CCDA Validation Result',
			    tenant_id: tenantId
			})), java.sql.Types.OTHER);
			stmt.setString(4, "CCDA_ACCEPT");	
			stmt.setString(5, "VALIDATION_FAILED");
		}
		//stmt.setNull(6, java.sql.Types.VARCHAR);

		if(operation === "saveOgCCDAPayload"){
			stmt.setNull(6, java.sql.Types.OTHER);
		} else {
			stmt.setObject(6, toJsonb(payloadJson), java.sql.Types.OTHER);	
		}

		if(operation == "saveValidationSuccess" || operation == "saveValidationFailed" || operation === "saveConversionSuccess"){
			stmt.setNull(7, java.sql.Types.OTHER);
		} else {
			stmt.setString(7, payloadJson);
		}			
		stmt.setNull(8, java.sql.Types.VARCHAR);
		stmt.setNull(9, java.sql.Types.OTHER);
		stmt.setNull(10, java.sql.Types.VARCHAR);
		stmt.setNull(11, java.sql.Types.VARCHAR);
		stmt.setNull(12, java.sql.Types.VARCHAR);
		stmt.setNull(13, java.sql.Types.VARCHAR);
		stmt.setNull(14, java.sql.Types.VARCHAR);
		stmt.setNull(15, java.sql.Types.VARCHAR);
		stmt.setNull(16, java.sql.Types.VARCHAR);
		stmt.setNull(17, java.sql.Types.TIMESTAMP_WITH_TIMEZONE);
		stmt.setNull(18, java.sql.Types.VARCHAR);
		stmt.setNull(19, java.sql.Types.BOOLEAN);
		stmt.setNull(20, java.sql.Types.VARCHAR);
		stmt.setNull(21, java.sql.Types.VARCHAR);
		stmt.setNull(22, java.sql.Types.VARCHAR);
		stmt.setNull(23, java.sql.Types.VARCHAR);
		stmt.setNull(24, java.sql.Types.VARCHAR);
		stmt.setNull(25, java.sql.Types.VARCHAR);
		stmt.setNull(26, java.sql.Types.VARCHAR);
		stmt.setNull(27, java.sql.Types.VARCHAR);
		stmt.setString(28, channelMap.get('filename'));
		stmt.setString(29, ccdaAuthoringDevice);

	    var result = stmt.execute();

	} catch (e) {
	    logger.error("Error executing stored procedure: " + e);
	} finally {
	    if (stmt != null) stmt.close();
	    if (conn != null) conn.close();
	    logger.info("DB connection closed.");
	}
}

/**
* Replacer function to remove empty values
*/
var interactionId = generateUuid();
channelMap.put('interactionId', interactionId);
var tenantId = $('headers').getHeader('X-TechBD-Tenant-ID');
var requestedPath = sourceMap.get('contextPath');

function removeEmptyValues(key, value) {
  // Remove values that are empty strings, null, undefined, or empty objects/arrays
  if (value === "" || value === null || value === undefined || 
      (typeof value === "object" && Object.keys(value).length === 0) ||
      (Array.isArray(value) && value.length === 0)) {
    return undefined; // Exclude the key from the result
  }
  return value; // Keep the value as is
}


/*
* Util function to generate json error message
*/
function getJsonInvalidOperationOutcome(errorMsg, code, severity) {
	if (!severity) { severity = "error";}
	return { "OperationOutcome": {
                    "validationResults": [
                        {
                            "operationOutcome": {
                                "resourceType": "OperationOutcome",
                                "interaction_id": channelMap.get('interactionId'),
                                "issue": [
                                    {
                                        "severity": severity,
                                        "code": code,
                                        "details": {
                                            "text": errorMsg
                                        }
                                    }
                                ]
                            }
                        }
                    ]
                }
            };
}

function sendDataLedgerSync(payload) {

    var apiUrl = LookupHelper.get("Config", "DATA_LEDGER_API_URL");

//Load from Lookup Manager (NOT sensitive)
var dataLedgerApiKey = LookupHelper.get("Config-sensitive", "TECHBD_NYEC_DATALEDGER_API_KEY");

//store real key into channelMap
channelMap.put("DATA_LEDGER_API_KEY", dataLedgerApiKey);
    if (apiUrl == null) {
        throw new Error("Environment variable DATA_LEDGER_API_URL is not set.");
    }
    if (dataLedgerApiKey == null) {
        throw new Error("Environment variable 'TECHBD_NYEC_DATALEDGER_API_KEY' is not set.");
    }

    try {
        var HttpClients = org.apache.http.impl.client.HttpClients;
        var HttpPost = org.apache.http.client.methods.HttpPost;
        var StringEntity = org.apache.http.entity.StringEntity;
        var EntityUtils = org.apache.http.util.EntityUtils;

        var httpClient = HttpClients.createDefault();
        var httpPost = new HttpPost(apiUrl);

        httpPost.setHeader("Content-Type", "application/json");
        httpPost.setHeader("Accept", "application/json");

        if (dataLedgerApiKey != null) {
        	httpPost.setHeader("x-api-key", dataLedgerApiKey); // ✅ Add x-api-key header
        }

        var entity = new StringEntity(payload, "UTF-8");
        httpPost.setEntity(entity);

        var response = httpClient.execute(httpPost);
        try {
            var statusCode = response.getStatusLine().getStatusCode();
            logger.info("sendDataLedgerSync response status: " + statusCode);
            var responseBody = EntityUtils.toString(response.getEntity());

            if (statusCode >= 200 && statusCode < 300) {
                logger.info("Data Ledger API Response: " + responseBody);
                return {
                    statusCode: statusCode,
                    body: responseBody
                };
            } else {
                logger.error("Data Ledger API Error. Status: " + statusCode + ", Response: " + responseBody);
                throw new Error("Request failed with status " + statusCode);
            }
        } finally {
            EntityUtils.consumeQuietly(response.getEntity());
        }
    } catch (error) {
        logger.error("Data Ledger API Request Failed: " + error.message);
        throw error;
    }
}

function saveDataLedgerSync(interactionId) {
	//*********** DATA LEDGER ***************
     var  currentTimestamEnd = new Date().toISOString().replace(/\.(\d{3})Z$/, function(match, millis) {
		// Add 3 more random digits to simulate microseconds
		var micros = millis + (Math.floor(Math.random() * 1000)).toString().padStart(3, '0');
		return '.' + micros + 'Z';
	});
	var payload = JSON.stringify({
        executedAt: currentTimestamEnd,
        actor: "TechBD",
        action: "sent", 
        destination: "Invalid - CCD Conversion Failed",
        dataId: interactionId,
        payloadType: "hrsnBundle"
  	});		

	// Check if tracking is enabled
	var trackingEnabled = LookupHelper.get("Config", "DATA_LEDGER_TRACKING");
	if (trackingEnabled != null && trackingEnabled.toLowerCase() == "true") {
	   logger.info("data ledger api call -BEGIN sent");
	   try {
        	sendDataLedgerSync(payload);
	   } catch (e) {
	        logger.error("Error occurred while sending data to Data Ledger: " + e.message);
	   }
	   logger.info("data ledger api call -END sent");
	} else {
	   logger.info("DATA_LEDGER_TRACKING is not true; skipping Data Ledger sync for sent.");
	}
	//*********** DATA LEDGER ***************
}			

// Function to validate addr dates
function validateAddrDates(addr, contextTag) {
	try {
		default xml namespace = "urn:hl7-org:v3"; // Set default namespace

		for each (var period in addr.useablePeriod) {
		  var low = period.low.@value.toString();
		  var high = period.high.@value.toString();

		  if (low && high && high !== "UNK") {
		      var lowDate = new Date(low.substring(0, 4), low.substring(4, 6) - 1, low.substring(6, 8));
		      var highDate = new Date(high.substring(0, 4), high.substring(4, 6) - 1, high.substring(6, 8));

		      if (highDate < lowDate) {
		          var errorMessage = 'Validation Error: high date (' + high + ') is earlier than low date (' + low + ') in ' + contextTag + '.useablePeriod.';
			     logger.error(errorMessage);
			     setErrorResponse(400, errorMessage); // Set the HTTP response status to 400 (Bad Request)
			     responseMap.put('finalResponse', JSON.stringify(getJsonInvalidOperationOutcome(errorMessage, "invalid")));
		       return;

		      }
		  }
		}
     } catch (error) {
        logger.error("Validation Error: " + error.message);
        return;
     }
}

function validateLowHighDates(xmlData) {
	try {	
	    var xml = new XML(xmlData);
	    default xml namespace = "urn:hl7-org:v3"; // Set default namespace

	    // 1. patientRole → addr
	    for each (var recordTarget in xml.recordTarget) {
	        var patientRole = recordTarget.patientRole;
	        for each (var addr in patientRole.addr) {
	            validateAddrDates(addr, "recordTarget.patientRole");
	        }
	    }

	    // 2. author → assignedAuthor → representedOrganization → addr
	    for each (var author in xml.author) {
	        var assignedAuthor = author.assignedAuthor;
	        if (assignedAuthor && assignedAuthor.representedOrganization) {
	            for each (var addr in assignedAuthor.representedOrganization.addr) {
	                validateAddrDates(addr, "author.assignedAuthor.representedOrganization");
	            }
	        }
	    }
	} catch (error) {
        logger.error("Validation Error: " + error.message);
        throw new Error("Validation Error: " + error.message);
     }
}

/**
 * Extract ClinicalDocument XML safely from raw input
 * @param rawXml - raw request body
 * @return extracted ClinicalDocument XML string OR null
 */
function extractClinicalDocumentFromRawXML(rawXml) {

    if (!rawXml) {
        return null;
    }

    try {
        // Normalize input
        rawXml = String(rawXml)
				    .replace(/^\uFEFF/, '')      // real BOM
				    .replace(/^ï»¿/, '')        // mis-decoded BOM
				    .trim();

        var xmlDeclaration = '<?xml version="1.0" encoding="UTF-8"?>\n';
        var hasXmlDeclaration = rawXml.indexOf('<?xml') !== -1;

        var startTag = hasXmlDeclaration ? '<?xml' : '<ClinicalDocument';
        var start = rawXml.indexOf(startTag);
        var end = rawXml.indexOf('</ClinicalDocument>');

        if (start === -1 || end === -1) {
            return null;
        }

        end += '</ClinicalDocument>'.length;
        var extractedXml = rawXml.substring(start, end);
        extractedXml = extractedXml.trim();  //Trim extra spaces

        // Add XML declaration if missing
        if (!hasXmlDeclaration) {
            extractedXml = xmlDeclaration + extractedXml;
        }

        return extractedXml;

    } catch (e) {
        logger.error("extractClinicalDocumentFromRawXML failed: " + e.message);
        return null;
    }
}

function extractBoundaries(rawCcdaXml) {
	try {
		logger.info("rawCcdaXml 1: " + rawCcdaXml);
		// Remove boundary
		var rawXml = String(rawCcdaXml)
				    .replace(/^\uFEFF/, '')      // real BOM
				    .replace(/^ï»¿/, '')        // mis-decoded BOM
				    .trim();		

	        // Extract everything after first blank line
	        var match = rawXml.match(/\r?\n\r?\n([\s\S]*)/);
	        if (match && match[1]) {
			    rawXml = match[1];
			    logger.info("rawXml 3: " + rawXml);
		   }

	        // Remove trailing boundary (last line starting with --)
	        rawXml = rawXml.replace(/\r?\n--.*--\r?\n?$/, '');
	        rawXml = rawXml.replace(/\r?\n--.*$/, '');

			if (rawXml.indexOf("Content-Disposition:") !== -1) {
			   // Find the index where Content-Disposition starts
			    var cdIndex = rawXml.indexOf("Content-Disposition:");

			    // Find the first newline AFTER Content-Disposition
			    var firstNewLineAfterCD = rawXml.indexOf("\n", cdIndex);

			    if (firstNewLineAfterCD !== -1) {
			        // Keep everything after that newline
			        rawXml = rawXml.substring(firstNewLineAfterCD + 1);

			    }
			}

			if (rawXml.indexOf("Content-Type:") !== -1) {
			   // Find the index where Content-Disposition starts
			    var cdIndex1 = rawXml.indexOf("Content-Type:");

			    // Find the first newline AFTER Content-Disposition
			    var firstNewLineAfterCD1 = rawXml.indexOf("\n", cdIndex1);

			    if (firstNewLineAfterCD1 !== -1) {
			        // Keep everything after that newline
			        rawXml = rawXml.substring(firstNewLineAfterCD1 + 1);
			    }
			}

	    rawXml = String(rawXml)
				    .replace(/^\uFEFF/, '')      // real BOM
				    .replace(/^ï»¿/, '')        // mis-decoded BOM
				    .trim();

	    return rawXml;
	} catch (e) {
        logger.error("extractBoundaries failed: " + e.message);
        return null;
    }
}

function extractClinicalDocument(rawXml) {
	try {
		var rawCcdaXml = rawXml;
		var extractedXml = extractClinicalDocumentFromRawXML(rawXml);

		if (!extractedXml || extractedXml.trim().length == 0 || extractedXml.trim() == '') {
			rawCcdaXml = extractBoundaries(rawXml);
		} else {
			rawCcdaXml = extractedXml;
		}

		// Save Original Payload
	     saveCcdaPayload(
	        interactionId,
	        tenantId,
	        requestedPath,
	        rawCcdaXml,
	        "saveOgCCDAPayload"
	     ); 

		if (!extractedXml || extractedXml.trim().length == 0 || extractedXml.trim() == '') {
		    var errorMsg = "Could not find ClinicalDocument boundaries in XML.";
		    var errorResponse = getJsonInvalidOperationOutcome(errorMsg, "invalid");

		    saveCcdaPayload(
		        interactionId,
		        tenantId,
		        requestedPath,
		        errorResponse,
		        "saveValidationFailed"
		    );

		    responseMap.put('finalResponse', JSON.stringify(errorResponse));		    
		    return;
		}

		channelMap.put('fileContent', extractedXml);
		return extractedXml;

	} catch (e) {
        logger.error("extractClinicalDocument failed: " + e.message);
        return null;
    }
}

function buildValidationErrorMessage(baseMessage, e) {
    var errorMessage = baseMessage;

    if (e.javaException) {
        errorMessage += " Message: " + e.javaException.getMessage();

        if (typeof e.javaException.getLineNumber === 'function') {
            errorMessage += " Line: " + e.javaException.getLineNumber();
        }

        if (typeof e.javaException.getColumnNumber === 'function') {
            errorMessage += " Column: " + e.javaException.getColumnNumber();
        }

    } else if (e.message) {
        errorMessage += " " + e.message;

    } else {
        errorMessage += " Unknown validation error occurred.";    }

    logger.error(errorMessage);
    return errorMessage;
}

function failAndExit(errorMsg, code, severity, interactionId, tenantId, requestedPath) {
    var outcome = getJsonInvalidOperationOutcome(errorMsg, code, severity);
    try {
		saveCcdaPayload(interactionId, tenantId, requestedPath, outcome, "saveValidationFailed");
		logger.info("Successfully saved validation failure information");
    } catch (e) {
        	logger.error("Failed to save validation failure: " + e.message);
    }

    responseMap.put('finalResponse', JSON.stringify(outcome));
    channelMap.put('jsonResult', JSON.stringify(outcome));
    logger.error("STOPPING PROCESSING: " + errorMsg);

    throw new Error("STOP_PROCESSING");
}

function applyPhiFilter(xmlString) {
    var xsltPath = channelMap.get('cdaPhiFilter');
    logger.info("xsltPath: " + xsltPath);

    // ← ADDED: Extract filename from path
    var fileNameWithExt = xsltPath.substring(xsltPath.lastIndexOf('/') + 1);
    var fileName = fileNameWithExt.replace('.xslt', '');
    logger.info("Extracted XSLT Key Name: " + fileName);

    // ← ADDED: Retrieve XSLT content from LookupHelper
    var xsltContent = LookupHelper.get("SchemaFiles", fileName);
    logger.info("Retrieved XSLT from LookupHelper");

    // ← ADDED: Validation check
    if (!xsltContent) {
        throw new Error("LookupManager: No XSLT found for key " + fileName);
    }

    // ← CHANGED: Create StreamSource from STRING CONTENT instead of FILE
    var xsltSource = new javax.xml.transform.stream.StreamSource(
        new java.io.StringReader(xsltContent)  // ← Using StringReader with content
    );

    var transformer = javax.xml.transform.TransformerFactory
        .newInstance()
        .newTransformer(xsltSource);  // ← Using xsltSource variable

    var writer = new java.io.StringWriter();
    transformer.transform(
        new javax.xml.transform.stream.StreamSource(new java.io.StringReader(xmlString)),
        new javax.xml.transform.stream.StreamResult(writer)
    );

    return writer.toString();
}

function validateAgainstXsd(xmlString) {
    var xsdFilePath = channelMap.get('xsdFilePath');
    logger.info("Using XSD file path: " + xsdFilePath);

    // ← ADDED: Extract filename from path
    var xsdFileName = xsdFilePath.substring(xsdFilePath.lastIndexOf('/') + 1);
    logger.info("Extracted XSD Lookup Key: " + xsdFileName);

    // ← ADDED: Create temp directory for XSD files
    var File = Packages.java.io.File;
    var FileWriter = Packages.java.io.FileWriter;

    var tempDir = new File("/tmp/cda_xsd_cache");
    if (!tempDir.exists()) {
        tempDir.mkdirs();
    }

    logger.info("Temp XSD folder = " + tempDir.getAbsolutePath());

    // ← ADDED: Load index.txt to get list of all XSD files
    logger.info("=== Loading XSD index from Lookup Manager ===");
    var rawIndex = LookupHelper.get("SchemaFiles", "index.txt");

    // ← ADDED: Normalize rawIndex to string
    var indexText = null;
    if (rawIndex == null) {
        logger.error("Lookup returned NULL for index.txt");
        indexText = "";
    } else if (typeof rawIndex === "object") {
        if (rawIndex.content && typeof rawIndex.content === "string") {
            indexText = rawIndex.content;
        } else {
            indexText = String(rawIndex);
        }
    } else if (typeof rawIndex === "string") {
        indexText = rawIndex;
    } else {
        indexText = String(rawIndex);
    }


    // ← ADDED: Parse XSD file list from index
    var xsdFiles = [];
    if (indexText.trim().length > 0) {
        xsdFiles = indexText
            .split(/\r?\n/)
            .map(function(line) { return line.trim(); })
            .filter(function(line) { return line.length > 0; });
    }

    logger.info("Final XSD list: " + JSON.stringify(xsdFiles));

    // ← ADDED: Write each XSD file from LookupHelper to temp directory
    for (var i = 0; i < xsdFiles.length; i++) {
        var name = xsdFiles[i];
        var content = LookupHelper.get("SchemaFiles", name);

        if (!content || content.trim().length === 0) {
            throw new Error("Missing XSD in LookupManager: " + name);
        }

        var f = new File(tempDir, name);
        var fw = new FileWriter(f);
        fw.write(content);
        fw.close();

        logger.info("Wrote XSD to temp: " + f.getAbsolutePath());
    }

    // ← CHANGED: Build schema from root XSD file in temp directory
    var schemaFactory = javax.xml.validation.SchemaFactory
        .newInstance(javax.xml.XMLConstants.W3C_XML_SCHEMA_NS_URI);

    var rootFile = new File(tempDir, xsdFileName);  // ← Using temp directory
    var schemaSource = new javax.xml.transform.stream.StreamSource(rootFile);
    var schema = schemaFactory.newSchema(schemaSource);
    var validator = schema.newValidator();

    // Validate XML (unchanged)
    logger.info("Starting XML validation against CDA schema...");
    validator.validate(
        new javax.xml.transform.stream.StreamSource(
            new java.io.StringReader(xmlString)
        )
    );
}

function convertCcdaToFhirBundle(phiFilteredXml) {

    // -----------------------------------
    // Load the XSLT template
    // -----------------------------------
    var xsltPath = channelMap.get('cdaPhiBundle');
    logger.info("xsltPath: " + xsltPath);

    var fileNameWithExt = xsltPath.substring(xsltPath.lastIndexOf('/') + 1);
    var fileName = fileNameWithExt.replace('.xslt', '');
    logger.info("Extracted XSLT Key Name: " + fileName);

    var xsltContent = LookupHelper.get("SchemaFiles", fileName);


    if (!xsltContent) {
        throw new Error("LookupManager: No XSLT found for key " + fileName);
    }

    // Convert XSLT to StreamSource
    var xsltSource = new javax.xml.transform.stream.StreamSource(
        new java.io.StringReader(xsltContent)
    );

    var transformerFactory = javax.xml.transform.TransformerFactory.newInstance();
    transformerFactory.setURIResolver(new javax.xml.transform.URIResolver({
    resolve: function(href, base) {
        // Extract key name from href (e.g. "cda-fhir-bundle-common-utils.xslt" → "cda-fhir-bundle-common-utils")
        var includedFileName = href.substring(href.lastIndexOf('/') + 1).replace('.xslt', '');
        logger.info("URIResolver resolving from LookupHelper: " + includedFileName);

        var includedContent = LookupHelper.get("SchemaFiles", includedFileName);

        if (!includedContent) {
            throw new Error("LookupManager: No XSLT found for included key: " + includedFileName);
        }

        return new javax.xml.transform.stream.StreamSource(
            new java.io.StringReader(includedContent)
        );
    }
}));       
    var transformer = transformerFactory.newTransformer(xsltSource);

    // -----------------------------------
    // Timestamp parameter
    // -----------------------------------
    var currentTimestamp = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SS'Z'").format(new java.util.Date());
    transformer.setParameter("currentTimestamp", currentTimestamp);

    transformer = set_fhir_resource_profile_urls(transformer); // Pass all the profile urls as parameters to XSLT

    // -----------------------------------
    // Base FHIR URL handling
    // -----------------------------------
    var customBaseFhirUrl = $('headers').getHeader('X-TechBD-Base-FHIR-URL');
    logger.info("X-TechBD-Base-FHIR-URL: " + customBaseFhirUrl);

    var validUrlsEnv = LookupHelper.get("Config", "MC_VALID_FHIR_URLS");
    logger.info("MC_VALID_FHIR_URLS from LookupHelper: " + validUrlsEnv);

    // Convert VALID_URLS to an array for validation
    var validUrls = validUrlsEnv ? validUrlsEnv.split(",").map(function(url) { return url.trim(); }) : [];

    // Check if the header value is valid
    if (customBaseFhirUrl !== null && customBaseFhirUrl.trim() != "") {
	    if (validUrls.includes(customBaseFhirUrl)) {
	        transformer.setParameter("baseFhirUrl", customBaseFhirUrl);
		   channelMap.put('baseFhirUrl', customBaseFhirUrl);
	    } else {
			var errorMessage = 'The provided X-TechBD-Base-FHIR-URL is invalid. Base-FHIR-URL taken from the environment variable.';
			logger.error(errorMessage);
	    }
    }

    // -----------------------------------
    // Transform CCDA → FHIR Bundle
    // -----------------------------------
    var writer = new java.io.StringWriter();
    transformer.transform(
        new javax.xml.transform.stream.StreamSource(
            new java.io.StringReader(phiFilteredXml)
        ),
        new javax.xml.transform.stream.StreamResult(writer)
    );

    // -----------------------------------
    // Clean JSON
    // -----------------------------------
    var rawJson = writer.toString();
    var jsonObject = JSON.parse(rawJson);
    var cleanedJsonString = JSON.stringify(jsonObject, removeEmptyValues, 2);	
    channelMap.put('ccd_fhir_bundle', cleanedJsonString);
    return cleanedJsonString;
}

