/**
* Util function to generate a hash string using sha-256 that can be used as the resource id in FHIR Bundle.
*/
function generateSHA256(inputString) {
    var md = Packages.java.security.MessageDigest.getInstance("SHA-256");
    md.update(inputString.getBytes("UTF-8"));   
    var digest = md.digest();
    return bytesToHex(digest);
}

function bytesToHex(byteArray) {
    var hexString = new java.lang.StringBuilder();
    for (var i = 0; i < byteArray.length; i++) {
        var hex = java.lang.Integer.toHexString(0xff & byteArray[i]);
        if (hex.length == 1) hexString.append('0');
        hexString.append(hex);
    }
    return hexString.toString();
}

function generateSHA256Id(resource, resourceName, resourceIdName, transformer, additionalString) {
    if (resource != undefined) { 
        // Get MRN and CIN from channelMap
        var mrn = channelMap.get('Patient-MRN') || "";
        var cin = channelMap.get('patientCIN') || "";
        var combinedText = mrn + cin;

        if (typeof additionalString !== 'undefined' && additionalString != null && additionalString !== '') {
            combinedText += additionalString;
        }

        var resourceText = resourceName + resource.toString().trim();
        combinedText += resourceText;

        // Generate SHA-256 hash
        var sha256Hash = generateSHA256(new java.lang.String(combinedText));
        transformer.setParameter(resourceIdName, sha256Hash);
    } else {
        logger.error(resourceName + " not found in the XML.");
    }

    return transformer;
}

function generateCompactSha256(sourceXml, resourceName, resourceIdName, transformer) {
    if (sourceXml != undefined) { 
	    var MessageDigest = Packages.java.security.MessageDigest;
	    var digest = MessageDigest.getInstance("SHA-256");

	    // Raw SHA-256 bytes
	    var hashBytes = digest.digest(new java.lang.String(sourceXml).getBytes("UTF-8"));

	    // Base64 URL-safe encoding
	    var sha256Hash = Packages.java.util.Base64
	        .getUrlEncoder()
	        .withoutPadding()
	        .encodeToString(hashBytes);
	    // Convert Java String to JavaScript String
    	    sha256Hash = String(sha256Hash).replace(/_/g, '-');

	    transformer.setParameter(resourceIdName, sha256Hash);
	    channelMap.put(resourceName + "_Resource_ID", sha256Hash);
	    logger.info(resourceName + " Resource_ID : " + sha256Hash);
    } else {
	        logger.error(resourceName + " not found.");
	    }

    return transformer;
}

function getPatientMRN(patientRoles) {
    var extensionAttr = '';
    var ehrVendor = channelMap.get('ehrVendor');

    /*function isSSNFormat(ext) {
    	    return (
	        ext && 
	        String.fromCharCode(ext.charCodeAt(3)) == '-' &&
	        String.fromCharCode(ext.charCodeAt(6)) == '-' &&
	        /^\d{3}-\d{2}-\d{4}$/.test(ext)
	    );
    }*/
    function isSSNFormat(ext) {
        return (
            ext &&
            ext.length === 11 &&
            ext.charAt(3) === '-' &&
            ext.charAt(6) === '-' &&
            /^\d{3}-\d{2}-\d{4}$/.test(ext)
        );
    }

	if (patientRoles != undefined) {
        var patientRole = patientRoles;
        var idNodes = patientRole.*::id;

        // Step 1: Check for Medent MRN
        if (ehrVendor == 'Medent') {
             for each (var idNode in idNodes) {
                var root = idNode.@root.toString();
                var ext  = idNode.@extension.toString().trim();

                if (
                    ext !== "" &&                                  // extension exists
                    root !== "2.16.840.1.113883.4.1" &&            // not SSN root
                    !isSSNFormat(ext)
                ) {
                    extensionAttr = ext;
                    logger.info("Patient MRN (Medent): " + extensionAttr);
                    break;
                }
            }
        }
	   // Step 2: Athenahealth MRN (from first ID, after "P-")
        else if (ehrVendor == 'Athenahealth') {
            for each (var idNode in idNodes) {
                var ext = idNode.@extension.toString().trim();

                // Only process if "P-" exists
                if (ext !== "" && ext.indexOf("P-") > -1) {
                    var mrnPart = ext.split("P-")[1]; // part after "P-"
                    // Check if the extracted part is not SSN
                    if (mrnPart && mrnPart.trim() !== "" && !isSSNFormat(mrnPart)) {
                        extensionAttr = mrnPart.trim();
                        logger.info("Patient MRN (Athenahealth): " + extensionAttr);
                        break; // Only first valid occurrence
                    }
                }
            }
        }
	   else if (ehrVendor == 'Epic'){	
        // Step 3: If Epic
            for each (var idNode in idNodes) {
                var root  = idNode.@root.toString();
                var ext   = idNode.@extension.toString().trim();
                var auth  = idNode.@assigningAuthorityName.toString().trim();

                if (
                    ext !== "" &&                                 // extension exists
                    auth === "EPI" &&
                    (root === "1.2.840.114350.1.13.570.2.7.5.737384.14" ||
                     root !== "1.2.840.114350.1.1") &&
                    !isSSNFormat(ext)
                ) {
                    extensionAttr = ext;
                    logger.info("Patient MRN (Epic): " + extensionAttr);
                    break;
                }
            }
	   }
	   else {
	   	//fallback to id.extension
	   	for each (var idNode in idNodes) {
                var ext = idNode.@extension.toString().trim();

                if (ext !== "" && !isSSNFormat(ext)) {
                    extensionAttr = ext;
                    logger.info("Patient MRN (Epic): " + extensionAttr);
                    break;
                }
            }
	   }        
    } else {
        logger.error("PatientRole not found in the XML.");
    }

    if (!extensionAttr || extensionAttr.trim() === "") {
       logger.warn("No matching MRN found.");
    }

    channelMap.put('Patient-MRN', extensionAttr);
}

function getEncounterEffectiveTime(encounterNodeList, returnFallBackTime) {
    var currentTime = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SS'Z'").format(new java.util.Date());
    var fallbackTime = '';
    if (returnFallBackTime != 'False') {
    		fallbackTime = currentTime;
    }

    if (!encounterNodeList || encounterNodeList.length === 0) {	
        return fallbackTime;
    }

    var encounterNode = encounterNodeList[0];

    // Try to get low/@value
    var lowValue = encounterNode.*::effectiveTime.*::low.@value.toString();
    if (lowValue && lowValue.length > 0) {
        return lowValue;
    }

    // Try to get effectiveTime/@value
    var directValue = encounterNode.*::effectiveTime.@value.toString();
    if (directValue && directValue.length > 0) {
        return directValue;
    }

    return fallbackTime;
}

function getCategoryDisplay(code) {
    switch (code) {
        case '71802-3':
            return 'Housing Instability';
        case '96778-6':
            return 'Inadequate Housing';
        case '96779-4':
            return 'Utility Insecurity';
        case '88122-7':
        case '88123-5':
            return 'Food Insecurity';
        case '93030-5':
            return 'Transportation Insecurity';
        case '96780-2':
            return 'Employment Status';
        case '96782-8':
        case '95618-5':
        case '95617-7':
        case '95616-9':
        case '95615-1':
        case '95614-4':
            return 'SDOH Category Unspecified';
        default:
            return 'SDOH Category Unspecified';
    }
}

function getCategoryCode(code) {
    switch (code) {
        case '71802-3':
            return 'housing-instability';
        case '96778-6':
            return 'inadequate-housing';
        case '96779-4':
            return 'utility-insecurity';
        case '88122-7':
        case '88123-5':
            return 'food-insecurity';
        case '93030-5':
            return 'transportation-insecurity';
        case '96780-2':
            return 'employment-status';
        case '96782-8':
        case '95618-5':
        case '95617-7':
        case '95616-9':
        case '95615-1':
        case '95614-4':
            return 'sdoh-category-unspecified';
        default:
            return null;
    }
}

// Define Namespace Resolver
function getObservationCategoryCodes(transformer, observations) {    
    var xml = new XML(observations); // Parse the source message as XML    
    var ccda = new Namespace("urn:hl7-org:v3"); // Define the CCDA namespace    
    default xml namespace = ccda; // Set default namespace so ccda tags can be used without prefix
    var ehrVendor = channelMap.get('ehrVendor');
    var codes;

    // Extract all observation code attributes
    if (ehrVendor == 'Medent' || ehrVendor == 'Athenahealth') {
	    codes = xml..component
	                   .structuredBody
	                   .component
	                   .section.(@ID == 'observations')
	                   .entry
	                   .observation
	                   .entryRelationship
	                   .observation
	                   .code.@code;
     } else if (ehrVendor == 'Epic') {
     	codes = xml..component
	                   .structuredBody
	                   .component
	                   .section.(@ID == 'observations')
	                   .entry
	                   .observation
	                   .entryRelationship
	                   .observation
	                   .entryRelationship
	                   .observation
	                   .code.@code;
     } else { 
   		codes = xml..component	
                  .structuredBody	
                  .component	
                  .section.(@ID == 'observations')	
                  .entry	
                  .observation	
                  .code.@code; 
   	}

	// collect unique category codes
	var categorySet = {};
	for (var i = 0; i < codes.length(); i++) {
	    var code = getCategoryCode(codes[i].toString().trim());
	    if (code && !(code in categorySet)) {
	        categorySet[code] = getCategoryDisplay(codes[i].toString().trim());  
	    }
	}

	var categoryJsonArray = [];
	for (var code in categorySet) {
	    categoryJsonArray.push({
	        code: code,
	        display: categorySet[code]
	    });
	}

	//Build Category json from Category codes to pass to the xslt file as transformer parameter
	var categoryXml = '[';
	for (var i = 0; i < categoryJsonArray.length; i++) {
	    categoryXml += '{' +
	        '"system": "http://hl7.org/fhir/us/sdoh-clinicalcare/CodeSystem/SDOHCC-CodeSystemTemporaryCodes",' +
	        '"code": "' + categoryJsonArray[i].code + '",' +
	        '"display": "' + categoryJsonArray[i].display + '"}';

	    if (i !== categoryJsonArray.length - 1) {
	        categoryXml += ',';
	    }
	}	
	categoryXml += ']';              

	// set context variable
	//msg['categoryXml'] = categoryXml;
	transformer.setParameter('categoryXml', categoryXml);
	return transformer;
}

function getMultipleAnswersForComponent(transformer, observations) {
	if (observations == null) {
        return transformer;
    }

    //var xml = new XML(observations); // Parse the source message as XML    
    var xml;
    try {
        xml = new XML(observations.toString()); // Safely parse the XML
    } catch (e) {
        logger.error("Error parsing observations XML: " + e.toString());
        return transformer;
    }
    var ccda = new Namespace("urn:hl7-org:v3"); // Define the CCDA namespace    
    default xml namespace = ccda; // Set default namespace so ccda tags can be used without prefix
    var matchingObservations = [];
    var ehrVendor = channelMap.get('ehrVendor');
    var codes;

    // Extract all observation code attributes
    try {
	    if (ehrVendor == 'Medent' || ehrVendor  == 'Athenahealth') {
		    matchingObservations = xml..component
		        .structuredBody
		        .component
		        .section.(@ID == 'observations')
		        .entry
		        .observation
		        .entryRelationship
		        .observation.(code.@code == '96778-6');
	     } else if (ehrVendor == 'Epic') {
	     	matchingObservations = xml..component
		        .structuredBody
		        .component
		        .section.(@ID == 'observations')
		        .entry
		        .observation
		        .entryRelationship
		        .observation
		        .entryRelationship
		        .observation.(code.@code == '96778-6');
	     } else {
	     	matchingObservations = xml..component
		        .structuredBody
		        .component
		        .section.(@ID == 'observations')
		        .entry
		        .observation.(code.@code == '96778-6');
	     }
     } catch (err) {
        logger.error("XPath error while extracting observations: " + err.toString());
        return transformer;
    }

	var seenCodes = {};
	var codingArray = [];

	for each (var obs in matchingObservations) {
	    for each (var val in obs.value) {
	        var code = val.@code.toString();
	        var display = val.@displayName.toString();

	        if (code && !seenCodes[code]) {
	            codingArray.push({
	                "system": "http://loinc.org",
	                "code": code,
	                "display": display
	            });
	            seenCodes[code] = true;
	        }
	    }
	}

	transformer.setParameter('componentAnswersXml', JSON.stringify(codingArray));
	return transformer;
}

function setBooleanHeaderFlag(headerName, transformer) {
    var value = channelMap.get(headerName);
    transformer.setParameter(
        headerName,
        (value && String(value).toLowerCase() === "true") ? "true" : "false"
    );
    return transformer;
}
// Define Namespace Resolver
function setResourceIdParameters(transformer) {
    	// Parse XML
	var sourceXml = $('phi_filtered_ccd');
	var xmlDoc = new XML(sourceXml);
	default xml namespace = "urn:hl7-org:v3";

	// Generate Bundle resource Id
	var ccda_fhir_bundle_id = channelMap.get('interactionId');
	if (ccda_fhir_bundle_id) {
		transformer.setParameter('bundleId', ccda_fhir_bundle_id);
		logger.info('bundleId : ' + ccda_fhir_bundle_id);
	}
	else {
		transformer = generateSHA256Id(xmlDoc, "ClinicalDocument", "bundleId", transformer);
	}

	// Extract `patientRole`
	var patientRoles = xmlDoc.*::recordTarget.*::patientRole[0];
	//getPatientMRN(patientRoles);
	transformer = generateSHA256Id(patientRoles, "patientRole", "patientResourceId", transformer);

	// Extract `consent`
	var consent = xmlDoc.*::authorization.*::consent[0];
	var currentTimestamp = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SS'Z'").format(new java.util.Date());
	transformer = generateSHA256Id(consent, "consent", "consentResourceId", transformer, currentTimestamp);

	// Extract `author (organization)`
	var author = xmlDoc.*::author[0];
	var organizationName = "";

	var ehrVendor = channelMap.get('ehrVendor');
	if (ehrVendor == 'Epic' || ehrVendor == 'Medent') {	
	    var encounterOrgName =
	        xmlDoc.*::component
	              .*::structuredBody
	              .*::component
	              .*::section.(@ID == 'encounters')
	              .*::entry[0]
	              .*::encounter
	              .*::participant.(@typeCode == 'LOC')[0]
	              .*::participantRole.(@classCode == 'SDLOC')
	              .*::playingEntity
	              .*::name[0];	
	    if (encounterOrgName != undefined && encounterOrgName.toString().trim() != "") {	
	        organizationName = encounterOrgName.toString().trim();

	    } else {	
	        var authorOrgName =
	            xmlDoc.*::author[0]
	                  .*::assignedAuthor
	                  .*::representedOrganization
	                  .*::name[0];	
	        if (authorOrgName != undefined && authorOrgName.toString().trim() != "") {
	            organizationName = authorOrgName.toString().trim();
	        }
	    }

	} else {	
	    var authorOrgName =
	        xmlDoc.*::author[0]
	              .*::assignedAuthor
	              .*::representedOrganization
	              .*::name[0];

	    if (authorOrgName != undefined && authorOrgName.toString().trim() != "") {
            organizationName = authorOrgName.toString().trim();
         }
	}

	transformer.setParameter('organizationName', organizationName);
	//logger.info('organizationName : ' + organizationName);
	transformer = generateSHA256Id(author, "Author", "organizationResourceId", transformer, organizationName);

	// Extract `Questionnaire` - used only for Generic CCDA files
	if (ehrVendor != 'Medent' && ehrVendor != 'Athenahealth' && ehrVendor != 'Epic') {
		var Questionnaire = xmlDoc.*::component
	                              .*::structuredBody
	                              .*::component
	                              .*::section.(@ID != 'sexualOrientation')
	                              .*::entry;
		transformer = generateSHA256Id(Questionnaire, "Questionnaire", "questionnaireResourceId", transformer);
	}	
	transformer.setParameter('patient-MRN', channelMap.get('Patient-MRN'));


	// Extract `observations`
/*	try {
		var observations = xmlDoc.*::component
	                         .*::structuredBody
	                         .*::component
	                         .*::section.(@ID == 'observations')
	                         .*::entry
	                         .*::observation
	                         .*::entryRelationship
	                         .*::observation
	                         .*::entryRelationship;
		transformer = generateSHA256Id(observations, "observations", "observationResourceSha256Id", transformer);
	} catch (e) {
	    logger.error("Error accessing Observations: " + e);
	}*/

	// Extract `sexualOrientation`
	var sexualOrientation = xmlDoc.*::component
                              .*::structuredBody
                              .*::component
                              .*::section.(@ID == 'sexualOrientation')
                              .*::entry
                              .*::observation;

	transformer = generateCompactSha256(sexualOrientation, "sexualOrientation", "sexualOrientationResourceId", transformer);	

	// Extract `encompassingEncounter`
	try {
		var encounter = xmlDoc.*::componentOf.*::encompassingEncounter;
		if (encounter != undefined && encounter.length() > 0) {
		    var encounterEffectiveTime = getEncounterEffectiveTime(encounter);	
		    transformer = generateSHA256Id(encounter, "encounter", "encounterResourceId", transformer, encounterEffectiveTime);
		} else {
		    // Try fallback to `encounter`
		    var encounters = xmlDoc.*::component
	                     .*::structuredBody
	                     .*::component
	                     .*::section.(@ID == 'encounters')
	                     .*::entry[0]
	                     .*::encounter;
		    if (encounters != undefined && encounters.length() > 0) {
		        var encounterEffectiveTime = getEncounterEffectiveTime(encounters);
		        transformer = generateSHA256Id(encounters, "encounter", "encounterResourceId", transformer, encounterEffectiveTime);
		    } else {
		        logger.error("Encounter resource not found in the XML.");
		    }
		}
	} catch (e) {
	    logger.error("Error accessing encounter: " + e);
	}

	/// ** Grouper Observation Resource ** ///
	// Get grouper Screening Code
     // For Epic files, use the value of the header variable,'X-TechBD-Screening-Code', as the Grouper Screening Code, otherwise use the LOINC code '100698-0'
     // For Medent files, take the value from code.code
     var grouperScreeningCode = channelMap.get('X-TechBD-Screening-Code');
	var grouperScreeningEffectiveTime = '';

	// Extract effectiveTime (COMMON for all vendors)
	try {
	    var observations = xmlDoc.*::component
	        .*::structuredBody
	        .*::component
	        .*::section.(@ID == 'observations')
	        .*::entry
	        .*::observation;

	    if (observations != undefined && observations.length() > 0) {
	        var obs = observations[0]; // first observation (same as [1] in XSLT)

	        if (obs.*::effectiveTime) {
	            var effTime = obs.*::effectiveTime.@value.toString().trim();

	            // fallback to low/@value
	            if (!effTime || effTime == '') {
	                effTime = obs.*::effectiveTime.*::low.@value.toString().trim();
	            }

	            grouperScreeningEffectiveTime = effTime;
	        }
	    }

	    logger.info("Grouper Screening Effective Time: " + grouperScreeningEffectiveTime);

	} catch (e) {
	    logger.error("Error extracting grouperScreeningEffectiveTime: " + e);
	}

	if ((channelMap.get('ehrVendor') == 'Epic' || channelMap.get('ehrVendor') == 'Athenahealth')
	    && (!grouperScreeningCode || grouperScreeningCode.trim() === '')) {

	    grouperScreeningCode = '100698-0';
	    logger.info("Defaulting grouperScreeningCode to 100698-0 for Epic");
	    	} else if ((channelMap.get('ehrVendor') == 'Medent')
	    && (!grouperScreeningCode || grouperScreeningCode.trim() === '')) {

	    // Try to extract from CCDA observations
	    try {
	        var observations = xmlDoc.*::component
	            .*::structuredBody
	            .*::component
	            .*::section.(@ID == 'observations')
	            .*::entry
	            .*::observation;

	        if (observations != undefined && observations.length() > 0) {
	            for each (var obs in observations) {
	                if (obs.*::code && obs.*::code.@code.toString().trim() != '') {
	                    grouperScreeningCode = obs.*::code.@code.toString().trim();
	                    logger.info("Using screening code from CCDA observation (Medent): " + grouperScreeningCode);
	                    break;
	                }
	            }
	        }

	    } catch (e) {
	        logger.error("Error extracting screening code/effectiveTime for Medent: " + e);
	    }

	    // Final fallback if still empty (matches XSLT)
	    if (!grouperScreeningCode || grouperScreeningCode.trim() === '') {
	        grouperScreeningCode = '96777-8';
	        logger.info("Defaulting grouperScreeningCode to 96777-8 for Medent");
	    }
	} else { // For general CCDA files
		//grouperScreeningEffectiveTime = '';
	}
	grouperScreeningCode = (grouperScreeningCode || '').trim();

	transformer.setParameter('grouperScreeningCode', String(grouperScreeningCode));
	logger.info('grouperScreeningCode' + " : " + grouperScreeningCode);

	// Get encounter effective time
	var encounterEffectiveTime = '';
	try {
		var encounter = xmlDoc.*::componentOf.*::encompassingEncounter;
		if (encounter != undefined && encounter.length() > 0) {
		    encounterEffectiveTime = getEncounterEffectiveTime(encounter, 'False');	
		} else {
		    // Try fallback to `encounter`
		    var encounters = xmlDoc.*::component
	                     .*::structuredBody
	                     .*::component
	                     .*::section.(@ID == 'encounters')
	                     .*::entry[0]
	                     .*::encounter;
		    if (encounters != undefined && encounters.length() > 0) {
		        encounterEffectiveTime = getEncounterEffectiveTime(encounters, 'False');
		    } else {
		        logger.error("Encounter resource not found in the XML.");
		    }
		}
	} catch (e) {
	    logger.error("Error accessing encounter: " + e);
	}

	// Generate the Grouper Observation Resource ID
	var mrn = (channelMap.get('Patient-MRN') || "").trim();
	var cin = (channelMap.get('patientCIN') || "").trim();
     var finalEffectiveTime = grouperScreeningEffectiveTime;

	if (!finalEffectiveTime || finalEffectiveTime.trim() === '') {
	    finalEffectiveTime = encounterEffectiveTime || '';
	    logger.info("Using encounterEffectiveTime as fallback for generating Grouper Resource ID : " + finalEffectiveTime);
	}

     logger.info("Hash Inputs → MRN: " + mrn + ", CIN: " + cin +
            ", Code: " + grouperScreeningCode +
            ", EffectiveTime: " + finalEffectiveTime);

     var combinedText = mrn + cin + grouperScreeningCode + finalEffectiveTime;

     transformer = generateCompactSha256(combinedText, "grouperObservation", "grouperObservationResourceSha256Id", transformer);   

     // Set category xml
     transformer = getObservationCategoryCodes(transformer, sourceXml); //observations
     transformer = getMultipleAnswersForComponent(transformer, sourceXml); //observations

	// Set part2, OMH and OPWDD flags
	transformer = setBooleanHeaderFlag('X-TechBD-Part2', transformer); // Set part2 flag
	transformer = setBooleanHeaderFlag('X-TechBD-OMH', transformer);	  // Set OMH flag
	transformer = setBooleanHeaderFlag('X-TechBD-OPWDD', transformer); // Set OPWDD flag
	// Extract `location`
     try {
	    var location;
	    var location_name;
	    var location_address;
		var locationSuccess = false;
		var isValidLocation = function(name, address) {
					        return (
					            name != null && name.toString().trim() !== '' &&
					            address != null && address.toString().trim() !== ''
					        );
					    };
	    // Primary location path: componentOf → encompassingEncounter → location → healthCareFacility → location
	    if (
	        xmlDoc.componentOf &&
	        xmlDoc.componentOf.encompassingEncounter &&
	        xmlDoc.componentOf.encompassingEncounter.location &&
	        xmlDoc.componentOf.encompassingEncounter.location.length() > 0 &&
	        xmlDoc.componentOf.encompassingEncounter.location[0].healthCareFacility &&
	        xmlDoc.componentOf.encompassingEncounter.location[0].healthCareFacility.location

	    ) {
	        location = xmlDoc.componentOf.encompassingEncounter.location[0].healthCareFacility.location;
	        location_name = location.name;
	        location_address = location.addr;
	        if (isValidLocation(location_name, location_address)) { locationSuccess = true; }
	    }

	    // Fallback path: structuredBody → encounters section → encounter → participant → participantRole → playingEntity → name
	if (!locationSuccess || channelMap.get('ehrVendor') == 'Medent') {
	        var section = xmlDoc.component.structuredBody.component.section.(@ID == 'encounters');
	        if (
	            section &&
	            section.entry &&
	            section.entry.length() > 0 &&
	            section.entry[0].encounter &&
	            section.entry[0].encounter.participant &&
	            section.entry[0].encounter.participant.length() > 0 &&
	            section.entry[0].encounter.participant[0].participantRole &&
	            section.entry[0].encounter.participant[0].participantRole.playingEntity
	        ) {
	            location = section.entry[0].encounter.participant[0].participantRole;
	            location_name = location.playingEntity.name;
	            location_address = location.addr;
	        	 if (isValidLocation(location_name, location_address)) { locationSuccess = true; }	        
	        	 }
	    }

	     if (locationSuccess && location) {
	        transformer = generateSHA256Id(location, "Location", "locationResourceId", transformer);
	    } else {
	        logger.info("Location not found in the XML.");
	    }

	} catch (e) {
	    logger.info("Error accessing location: " + e);
	}

	return transformer;
}

/**
* Util function to get FHIR resource profile URLs and set as parameters to the transformer which converts the XML file to FHIR Bundle.
*/
function set_profile_url(transformer, profileUrl, urlEnv, metaProfileUrlName) {
	if(profileUrl != null) {
		transformer.setParameter(metaProfileUrlName, profileUrl);
		channelMap.put(metaProfileUrlName, profileUrl);
		logger.info(metaProfileUrlName + ": " + profileUrl);
	} else {
		var errorMessage = urlEnv + ' variable is not set';
		logger.error(errorMessage);
		setErrorResponse(500, errorMessage); // Set the HTTP response status to 500 (Server error)
		throw errorMessage; // Stop further processing by throwing an exception
	}
	return transformer;
}

function set_fhir_resource_profile_urls(transformer) {
	var baseFhirUrl = LookupHelper.get("Config", "BASE_FHIR_URL");   
	var bundleMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_BUNDLE"); 
	var patientMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_PATIENT");
	var encounterMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_ENCOUNTER");
	var consentMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_CONSENT"); 
	var organizationMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_ORGANIZATION");
	var observationMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_OBSERVATION");
	var observationSexualOrientationMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_SEXUAL_ORIENTATION");
	var questionnaireMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_QUESTIONNAIRE");
	var questionnaireResponseMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_QUESTIONNAIRE_RESPONSE");
	var practitionerMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_PRACTITIONER");
	var procedureMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_PROCEDURE");
	var locationMetaProfileUrl = LookupHelper.get("Config", "PROFILE_URL_LOCATION");

	transformer = set_profile_url(transformer, baseFhirUrl, 'BASE_FHIR_URL', 'baseFhirUrl');
	transformer = set_profile_url(transformer, bundleMetaProfileUrl, 'PROFILE_URL_BUNDLE', 'bundleMetaProfileUrl');
	transformer = set_profile_url(transformer, patientMetaProfileUrl, 'PROFILE_URL_PATIENT', 'patientMetaProfileUrl');
	transformer = set_profile_url(transformer, encounterMetaProfileUrl, 'PROFILE_URL_ENCOUNTER', 'encounterMetaProfileUrl');
	transformer = set_profile_url(transformer, consentMetaProfileUrl, 'PROFILE_URL_CONSENT', 'consentMetaProfileUrl');
	transformer = set_profile_url(transformer, organizationMetaProfileUrl, 'PROFILE_URL_ORGANIZATION', 'organizationMetaProfileUrl');
	transformer = set_profile_url(transformer, observationMetaProfileUrl, 'PROFILE_URL_OBSERVATION', 'observationMetaProfileUrl');
	transformer = set_profile_url(transformer, observationSexualOrientationMetaProfileUrl, 'PROFILE_URL_SEXUAL_ORIENTATION', 'observationSexualOrientationMetaProfileUrl');
	transformer = set_profile_url(transformer, questionnaireMetaProfileUrl, 'PROFILE_URL_QUESTIONNAIRE', 'questionnaireMetaProfileUrl');
	transformer = set_profile_url(transformer, questionnaireResponseMetaProfileUrl, 'PROFILE_URL_QUESTIONNAIRE_RESPONSE', 'questionnaireResponseMetaProfileUrl');
	transformer = set_profile_url(transformer, practitionerMetaProfileUrl, 'PROFILE_URL_PRACTITIONER', 'practitionerMetaProfileUrl');
	transformer = set_profile_url(transformer, procedureMetaProfileUrl, 'PROFILE_URL_PROCEDURE', 'procedureMetaProfileUrl');
	transformer = set_profile_url(transformer, locationMetaProfileUrl, 'PROFILE_URL_LOCATION', 'locationMetaProfileUrl');

	transformer.setParameter("patientCIN", channelMap.get('patientCIN')); // Pass the parameter to XSLT
	if (channelMap.get('organizationNPI')) {
		transformer.setParameter("organizationNPI", channelMap.get('organizationNPI')); // Pass the parameter to XSLT
	}		
	if (channelMap.get('organizationTIN')) {
		transformer.setParameter("organizationTIN", channelMap.get('organizationTIN')); // Pass the parameter to XSLT
	}
	if (channelMap.get('facilityID')) {
		transformer.setParameter("facilityID", channelMap.get('facilityID')); // Pass the parameter to XSLT
	}
	if (channelMap.get('encounterType')) {
		transformer.setParameter("encounterType", channelMap.get('encounterType')); // Pass the parameter to XSLT
	}

	//Generate resource ids and set as parameter to pass to xslt 
	transformer = setResourceIdParameters(transformer);

	return transformer;
}

/**
*	Function to Check the existance of Consent section in the CCDA xml file and set the header variable 'X-TechBD-Elaboration'.
*	This function is called while the /Bundle request
*/
function getConsentResourceStatus(sourceXml) {
	try {
		var consentInfo = {};
	    	consentInfo.code = 'Consent-Status';
	    	consentInfo.status = "TechBD-Generated";
	    	var ehrVendor = (channelMap.get('ehrVendor') || '').toLowerCase();
	    	var ccdaConsentCode = ehrVendor == 'athenahealth' ? '29762-2' : '47519-4';
		var xmlDoc = new XML(sourceXml); // Convert XML string to XML object			
		default xml namespace = "urn:hl7-org:v3"; // Default namespace for HL7 documents
	var xsi = new Namespace("xsi", "http://www.w3.org/2001/XMLSchema-instance");
		// If consent section is there, the consentInfo.status should be "provided".
		var consentSection = xmlDoc.*::authorization.*::consent;
		if (consentSection != null && consentSection.length() > 0) {
			consentInfo.status = "provided";
		}
		else {
			// Iterate through all <section> elements
			for each (var section in xmlDoc..section) {
			    var sectionCode = section.code.@code.toString();

			    if (sectionCode == ccdaConsentCode) {
			        // Inside the correct section
			        for each (var entry in section.entry) {
			            for each (var observation in entry.observation) {
			                for each (var entryRel in observation.entryRelationship) {
			                    for each (var nestedObs in entryRel.observation) {
			                        var obsCode = nestedObs.code.@code.toString();
			                        if (obsCode == "105511-0") {
			                            consentInfo.status = "provided";
			                            break;
			                        } else if (ehrVendor == 'athenahealth') {
			                        	    var obsRoot = nestedObs.templateId.@root.toString().trim();
			                        	    var obsValueDisplayName = nestedObs.value.@displayName.toString().trim().toLowerCase();
			                        	    var xsiType = nestedObs.value.@xsi::type.toString();
				                        if (obsRoot == '2.16.840.1.113883.10.20.22.4.86' 
				                        		&& (obsValueDisplayName == "permit" || obsValueDisplayName == "deny") 
				                        		&& xsiType == "CD") {
				                        	   consentInfo.status = "provided";
				                            break;
				                        }
			                        }
			                    }
			                }
			            }
			        }
			    }
			}
		}		
		// Convert to JSON string (optional, for sending/logging)
		var consentJsonString = JSON.stringify(consentInfo);

		channelMap.put('elaboration', consentJsonString);
	} catch (e) {
        var errorMsg;
        if (e instanceof JavaException) {
           errorMsg = "Error parsing Consent Resource: " + e.toString();
        } else {
           errorMsg = "Unexpected error during getting Consent Resource: " + e.message;
        }
        logger.error(errorMsg);

        // Failure: Return an OperationOutcome JSON response with validation errors
        responseMap.put('finalResponse', JSON.stringify(getJsonInvalidOperationOutcome(errorMsg, "invalid")));

        throw new Error(errorMsg);
     }
}

/**
 * Validate mandatory fields for CCDA → FHIR conversion
 * @return null OR OperationOutcome JSON
 */
function validateMandatoryFields() {
    	var sourceXml = channelMap.get('phi_filtered_ccd');
	var ccdaXml = new XML(sourceXml);
	default xml namespace = "urn:hl7-org:v3";
	var errors = [];

	var patientRole = ccdaXml.*::recordTarget.*::patientRole[0];
	getPatientMRN(patientRole);

    	// --------------------------------------------------------------------------------------------------------------------
    	// I. Patient Resource
    	// -----------------------------
    	// 1. PatientRole existence
    	try {	   
    		if (!patientRole || patientRole.length() === 0) {
	        errors.push("PatientRole is missing. FHIR Patient resource cannot be created.");
	    	} else {
	        var patient = patientRole.*::patient[0];
	        // 2. Patient Name
	        var name = patient ? patient.*::name[0] : null;
	        var givenName = name ? name.*::given.toString() : "";
	        var familyName = name ? name.*::family.toString() : "";
	        if (!givenName) { errors.push("Patient name (given) -> ClinicalDocument.recordTarget.patientRole.patient.name.given."); }
		   if (!familyName) { errors.push("Patient name (family) -> ClinicalDocument.recordTarget.patientRole.patient.name.family."); }

	        // 3. Gender
	        var genderValue = "";
		   if (patient) {
			    var genderEl = patient.*::administrativeGenderCode[0];

			    if (genderEl) {
			        // Prefer code
			        if (genderEl.@code && genderEl.@code.toString().trim() !== "") {
			            genderValue = genderEl.@code.toString().trim();
			        }
			        // Fallback to displayName
			        else if (genderEl.@displayName && genderEl.@displayName.toString().trim() !== "") {
			            genderValue = genderEl.@displayName.toString().trim();
			        }
			    }
		   }			
		   if (genderValue === "") {
			    errors.push(
			        "Patient gender -> ClinicalDocument.recordTarget.patientRole.patient.administrativeGenderCode."
			    );
		   }

	        // 4. Birth Date
	        var birthDate = "";
		   if (patient) {
			    var birthEl = patient.*::birthTime[0];
			    if (birthEl && birthEl.@value) {
			        birthDate = birthEl.@value.toString();
			    }
		   }			
		   if (birthDate === "") {
			    errors.push("Patient birthDate -> ClinicalDocument.recordTarget.patientRole.patient.birthTime.");
		   }

		   // 5. Patient MRN
	       var patientMrn = channelMap.get('Patient-MRN');
		   if (patientMrn === null || String(patientMrn).trim() === "") {
		   		errors.push("Patient MRN -> ClinicalDocument.recordTarget.patientRole.id.extension.");
		   }
	    	}
    	} catch (e) {
	    logger.error("Error accessing patientRole: " + e);
	}

    	// --------------------------------------------------------------------------------------------------------------------
    	// II. Encounter Resource
    	// -----------------------------
    	/*try {
	     var encompassingEncounter = ccdaXml.*::componentOf.*::encompassingEncounter[0];
		if (encompassingEncounter) {
		    // 1. Encounter class
		    var encounterClass = encompassingEncounter.*::code.@code.toString();
		    if (!encounterClass) {
		        errors.push("Encounter class -> ClinicalDocument.componentOf.encompassingEncounter.code.code.");
		    }		
		} else {
			logger.info("encompassingEncounter not found");

		    // Try fallback to `encounter`
		    var encounters = ccdaXml.*::component
	                     .*::structuredBody
	                     .*::component
	                     .*::section.(@ID == 'encounters')
	                     .*::entry[0]
	                     .*::encounter;
		    if (encounters) {
			    // 1. Encounter class
			    var encounterClass = encounters.*::code.@code.toString();
			    if (!encounterClass) {
			        errors.push("Encounter class -> ClinicalDocument.component.structuredBody.component.section[code.code='46240-8'].entry[0].encounter.code.code.");
			    }			        
		    } else {
		        logger.error("Encounter Entry not found in the XML.");
		    }
		}
	} catch (e) {
	    logger.error("Error accessing encounter: " + e);
	}*/

	// --------------------------------------------------------------------------------------------------------------------
    	// III. Organization (Location / Author Organization)
	// -----------------------------
	var organizationName = "";
	var organizationNameXPath = "";

	// 1.️ Try Encounter → Location → Organization name
	try {
	    var orgFromEncounter =
	        ccdaXml.*::component
	               .*::structuredBody
	               .*::component
	               .*::section.(@ID == "encounters")
	               .*::entry[0]
	               .*::encounter
	               .*::participant.(@typeCode == "LOC")
	               .*::participantRole.(@classCode == "SDLOC")
	               .*::playingEntity
	               .*::name[0];

	    if (orgFromEncounter) {
	        organizationName = orgFromEncounter.toString().trim();	      
	    }
	} catch (e) {
	    logger.warn("Encounter organization name not found.");
	}

	// 2.️ Fallback → assignedAuthor → representedOrganization → name
	if (organizationName === "") {
	    try {
	        var orgFromAuthor =
	            ccdaXml.*::author[0]
	                   .*::assignedAuthor
	                   .*::representedOrganization
	                   .*::name[0];

	        if (orgFromAuthor) {
	            organizationName = orgFromAuthor.toString().trim();
	        }
	    } catch (e) {
	        logger.warn("Author organization name not found.");
	    }
	}

	// 3.️ Mandatory validation
	organizationNameXPath = "ClinicalDocument.component.structuredBody.component.section[code.code='46240-8'].entry[0].encounter.participant.participantRole.playingEntity.name. OR ClinicalDocument.author.assignedAuthor.representedOrganization.name.";
	if (organizationName === "") {
	    errors.push("Organization name -> " + organizationNameXPath);
	}

	logger.info("Organization Name resolved as: " + organizationName);

    // -----------------------------
    // Return OperationOutcome if errors exist
    // -----------------------------
    if (errors.length > 0) {
    	   logger.info(errors.toString());			
        return errors;
    }

    return null; // validation passed
}

